#include <iostream>

using namespace std;

// Symbol    Value
// I          1
// V          5
// X          10
// L          50
// C          100
// D          500
// M          1,000

string asRoman(int num, string sign)
{
	string res;

	for (int i = 0; i < num; ++i) {
		res += sign;
	}

	return res;
}

string reverse(string sRomanNumber)
{
	string res;

	for (int i = int(sRomanNumber.size()) - 1; i >= 0; --i)
	{
		res += sRomanNumber[i];
	}

	return res;
}

int to_int(char str) {
	int res;

	if (str == '0') res = 0;
	if (str == '1') res = 1;
	if (str == '2') res = 2;
	if (str == '3') res = 3;
	if (str == '4') res = 4;
	if (str == '5') res = 5;
	if (str == '6') res = 6;
	if (str == '7') res = 7;
	if (str == '8') res = 8;
	if (str == '9') res = 9;

	return res;
}

string solution(int iNumber)
{
	string sNumber = reverse(to_string(iNumber)), res;
	string sRomanNums[4][2] = {
		{"I", "V"},
		{"X", "L"},
		{"C", "D"},
		{"M", ""}
	};

	for (int i = 0; i < int(sNumber.size()); ++i)
	{
		int iCurrentNum = to_int(sNumber[i]);
		string temp1, temp2;

		if (iCurrentNum) {
			int iBalance = iCurrentNum / 5, tempNum = iCurrentNum;

			if (iBalance) {
				temp2 = asRoman(iBalance, sRomanNums[i][1]);
				tempNum -= 5;
			}

			temp1 = asRoman(tempNum, sRomanNums[i][0]);

			if (int(temp1.size()) > 3) {
				temp1 = "", temp2 = "";

				if (iCurrentNum < 5) {
					iBalance = 5 - iCurrentNum;

					temp2 = asRoman(iBalance, sRomanNums[i][0]);
					temp1 = asRoman(1, sRomanNums[i][1]);
				} else {
					iBalance = 10 - iCurrentNum;

					temp2 = asRoman(iBalance, sRomanNums[i][0]);
					temp1 = asRoman(1, sRomanNums[i+1 < int(sNumber.size()) ? i + 1 : int(sNumber.size())][0]);
				}
			}
		}

		res += reverse(temp2 + temp1);
	}

	return reverse(res);
}

int main()
{
	int iNumber;

	cout << "Enter number: ";
	cin >> iNumber;

	cout << solution(iNumber) << endl;

	system("pause > nul");
	return 0;
}

Мы можем производить так называемое множественное наследование:

class Base
{
	public:
		void showBase()
		{
			cout << "base" << endl;
		}
};

class Main
{
	public:
		void showMain()
		{
			cout << "main" << endl;
		}
};

class New : public Main, public Base 
{
	public:
		void show()
		{
			showBase();
			showMain();
		}
};

При таком типе наследования класс "New" будет фактически содержать в себе атрибуты классов "Base" и "Main". То есть запись выше эквивалентна:

class New
{
	public:
		void showMain()
		{
			cout << "main" << endl;
		}

		void showBase()
		{
			cout << "base" << endl;
		}

		void show()
		{
			showBase();
			showMain();
		}
};

Но это уже тема наследования, а ты должен её знать, желательно :D

Если у базовых классов будут совпадать методы, то их вызов в дочернем классе будет невозможен. Вот пример:

class Base
{
	public:
		void use() {
			cout << "Base" << endl;
		}
};

class Main
{
	public:
		void use()
		{
			cout << "Main" << endl;
		}
};

class New : public Main, public Base 
{
	public:
		void show()
		{
			use(); // ERROR
		}
};

Для вызова внутри дочернего класса нужно будет использовать:

::Main::use();

или

::Base::use();

Если же будет необходимо вызвать один из схожих методов вне класса, то нужно будет произвести приведение типов (в нашем случае приведение типа "New" к "Main" или "Base"):

int main()
{
	New n;

	((Main)n).use(); // Main
	((Base)n).use(); // Base

	system("pause > nul");
	return 0;
}

P.S. приведение типа обернуто в скобки для того, чтобы эта операция прошла первой, а после неё уже вызов метода "use".

При множественном наследовании порядок вызова конструкторов будет таким:

первый наследуемый класс, второй наследуемый класс ... класс наследник

Вот пример для лучшего понимания:

class Base
{
	public:
		Base() {
			cout << "base constructor" << endl;
		}
};

class Main
{
	public:
		Main() {
			cout << "main constructor" << endl;
		}
};

class New : public Main, public Base 
{
	public:
		New() {
			cout << "new constructor" << endl;
		}
};

При создании экземпляра класса "New" мы увидим в консоли:

main constructor
base constructor
new constructor

Вызов деструкторов будет обратный.

Чтобы понять, зачем нужны виртуальные методы и их переопределение ключевым словом "override", я написал небольшон разъяснение..

class Gun {
	public:
		void shoot() {
			cout << "bang!" << endl;
		}
};

class M4 : public Gun {
	public:
		void shoot() {
			cout << "tra-ta-ta!" << endl;
		}
};

Если мы присвоим ссылку на экзмепляр класса "M4" указателю типа "Gun", то, вызвав у этого указателя метод "shoot", мы получим в консоль "bang!". Сложно понять? Тогда просто взгляни:

int main() {
	M4 m4;

	Gun *gun = &m4;

	gun.shoot(); // bang!

	system("pause > nul");
	return 0;
}

Но, почему мы получили "bang!", если присвоили экземляр класса "M4", у которого метод "shoot" выводит в консоль "tra-ta-ta!"? Давай воспользуемся ключевыми словами "virtual" и "override", чтобы исправить это:

class Gun {
	virtual public:
		void shoot() {
			cout << "bang!" << endl;
		}
};

class M4 : public Gun {
	public:
		void shoot() override {
			cout << "tra-ta-ta!" << endl;
		}
};

Теперь, выполним код ниже и получим..

M4 m4;

Gun *gun = &m4;

gun.shoot(); // tra-ta-ta!

Думаю всё равно не особо понятно зачем это. Давай кое-что более приближённое к реальным задачам:

class Gun {
	public:
		virtual void shoot() {
			cout << "bang!" << endl;
		}
};

class M4 : public Gun {
	public:
		void shoot() override {
			cout << "tra-ta-ta!" << endl;
		}
};

class MachineGun : public Gun {
	public:
		void shoot() override {
			cout << "bang! bang! bang!" << endl;
		}
};

class Player {
	public:
		void shoot(Gun *gun) {
			gun -> shoot();
		}
};

Интересно, не правда ли? Давай теперь разберёмся в том, что я сделал :D

Мы имеем класс родитель "Gun" и два дочерних класса "M4" и "MachineGun", наследованные от него. Так же у нас есть класс "Player", который имеет метод "shoot", принимающий на вход указатель на объект типа "Gun" и вызывающий у него метод "shoot" (если мы имеем указатель на объект, необходимо вызывать методы с помощью оператора "->"). Теперь смотри, в чем суть виртуальных методов.. Наш игрок может получать на вход методу "shoot" любые объекты, наследованные от класса "Gun". Тем самым мы можем сделать так:

int main() {
	M4 m4;

	Player player;
	player.shoot(&m4); // tra-ta-ta!

	system("pause > nul");
	return 0;
}

И так тоже можем..

int main() {
	MachineGun mg;

	Player player;
	player.shoot(&mg); // bang! bang! bang!

	system("pause > nul");
	return 0;
}

Круто, не правда ли?)

Если ты внимателен, у тебя может появится вопрос, почему бы просто не сделать так..

class Player {
	public:
		template <typename T>
		void shoot(T *gun) {
			gun -> shoot();
		}
};

Можно и так, тогда и не нужны будут никакие "виртуалы" и "оверрайды". Каждому своё, как говориться!)

Так же, на последок, взгляни на следующий код:

class A {
	public:
		virtual string print() {
			return "SOME TEXT";
		}
};

class B : public A {
	public:
		string print() override {
			return print();
		}
};

int main() {
	B b;

	cout << b.print() << endl;

	system("pause > nul");
	return 0;
}

Как думаешь, что будет по итогу? Думаю ты понял, что в дочернем классе "B" мы переопределили метод "print" базового класса "A". Но, что же мы делаем внутри переопределённого метода? Именно, вызываем метод "ptint". Казалось бы, всё нормально, но, так как данный метод был переопределён, мы фактически создадим рекурсию, вызывая переопределённую функцию снова и снова. Понял теперь, что мы хотим сделать? Верно, мы хотим вызвать виртуальный метод базового класса. Чтобы это сделать, мы должны использовать специальный синтаксис:

class A {
	public:
		virtual string print() {
			return "SOME TEXT";
		}
};

class B : public A {
	public:
		string print() override {
			return ::A::print();
		}
};

int main() {
	B b;

	cout << b.print() << endl; // SOME TEXT

	system("pause > nul");
	return 0;
}

То есть, при помощи "::A::methodName" мы можем достучаться до виртуального метода базового класса.

Давай, перед объяснением, я поясню, что делегирующие конструкторы - чисто синтаксический сахар, который облегчает работу с конструкторами. Теперь гляди пример:

class Human {
	public:
		Human(string name) {
			this -> name = name;
			this -> age = 0;
			this -> height = 0;
		}

		Human(string name, int age) {
			this -> name = "";
			this -> age = age;
			this -> height = 0;
		}

		Human(string name, int age, int height) {
			this -> name = "";
			this -> age = 0;
			this -> height = height;
		}

	private:
		string name;
		int age;
		int height;
};

У нас есть класс "Human", который имеет поля "name", "age" и "height". Так же у нас есть конструкторы. Всего их три:

1. если известно только имя;
2. если известны имя и возраст;
3. если известны имя, возраст и рост.

Так вот суть делегирующих конструкторов заключается в том, что мы можем упростить реализацию каждого конструктора посредством вызова других конструкторов. Ахах, лучше просто посмотри:

class Human {
	public:
		Human(string name) {
			this -> name = name;
			this -> age = 0;
			this -> height = 0;
		}

		Human(string name, int age):Human(name) {
			this -> age = age;
		}

		Human(string name, int age, int height):Human(name, age) {
			this -> height = height;
		}

	private:
		string name;
		int age;
		int height;
};

Как будет происходить логика выше? Давай рассмотрим все случаи:

1. Human human("ZER");

Вызывается первый конструктор (считаю сверху вниз) -> Устанавливается значение "name" по приходящему параметру "name", остальные значения в нуль.

2. Human human("ZER", 10);

Вызывается второй конструктор -> Вызывается первый конструктор, на вход передаётся приходящее значение "name" -> первый конструктор устанавливает значение "name", остальные значения в нуль -> второй конструктор устанавливает значение "age" по приходящему значению "age".

3. Human human("ZER", 10, 150);

Вызывается третий конструктор -> Вызывается второй конструктор, на вход передаётся приходящие значения "name" и "age" -> Вызывается первый конструктор, на вход передаётся приходящее значение "name" -> первый конструктор устанавливает значение "name", остальные значения в нуль -> второй конструктор устанавливает значение "age" по приходящему значению "age" -> третий конструктор устанавливает значение "height" по приходящему значению "height".

Думаю это довольно круто)

Суть абстрактных классов в том, что они имеют так называемые "чистые" виртуальные методы. Имея чистый виртуальный метод класс становиться абстрактным. Создать экземпляр абстрактного класса нельзя. Вот пример:

// abstract class
class Weapon {
	virtual void shoot() = 0;
};

class M4 : public Weapon {
	public:
		void shoot() override {
			cout << "tra-ta-ta!" << endl;
		}
};

class MachineGun : public Weapon {
	public:
		void shoot() override {
			cout << "bang! bang! bang!" << endl;
		}
};

Таким образом класс "Weapon" становится абстрактным, ведь его метод "shoot" является чисто виртуальным.

Чисто виртуальные методы - виртуальные методы, не имеющие реализации.

То есть теперь, если мы попытаемся сделать так..

Weapon wp;

..компилятор нам не позволит и выдаст оишбку.

Абстрактные классы мы можем лишь наследовать.

Работая с деструкторами классов мы так же можем делать их виртуальными. Где это может пригодиться? Вот пример без виртуального деструктора, чтобы понять проблему.

class A {
	public:
		A() {
			cout << "constructor A" << endl;
		}

		~A() {
			cout << "destructor A" << endl;
		}
};

class B : public A {
	public:
		B() {
			cout << "constructor B" << endl;
		}

		~B() {
			cout << "destructor B" << endl;
		}
};

int main() {
	A *aptr = new B;

	delete aptr;

	return 0;
}

Вывод будет таким:

constructor A
constructor B
destructor A

Но, где же деструктор класса "B"? Так вот если ты помнишь тему виртуальных методов, то ты поймёшь, что, в примере выше, мы фактически вызываем деструктор класса "A", ведь деструктор переопределён не был. Чтобы получит более корректный результат, мы должны сделать деструктор класса "A" виртуальным, а у класса "B" обозначить его меткой переопределения - override.

class A {
	public:
		A() {
			cout << "constructor A" << endl;
		}

		virtual ~A() {
			cout << "destructor A" << endl;
		}
};

class B : public A {
	public:
		B() {
			cout << "constructor B" << endl;
		}

		~B() override {
			cout << "destructor B" << endl;
		}
};

int main() {
	A *aptr = new B;

	delete aptr;

	return 0;
}

Вывод:

constructor A
constructor B
destructor B
destructor A

Как мы этого и хотели) А что, если мы хотим сделать деструктор класса "A" чисто виртуальным (без какой либо реализации). Для этого мы должны сделать то же, что и с чисто виртуальными методами:

class A {
	public:
		A() {
			cout << "constructor A" << endl;
		}

		virtual ~A() = 0;
};

Но такой код выдаст нам ошибку, ведь синтаксис создания чисто виртуальных деструкторов отличается от создания чисто виртуальных методов. Нам нужно дополнительно вынести пустую реализацию деструктора за пределы класса:

class A {
	public:
		A() {
			cout << "constructor A" << endl;
		}

		virtual ~A() = 0;
};

A::~A(){};

Вывод:

constructor A
constructor B
destructor B

Но, надо понимать, что мы не просто ничего не делаем в деструкторе базового класса "A", но и обеспечиваем создание абстрактного класса. Об абстрактных классах почитай по тегу "#abstraction".

И тааак, полиморфизм. Для начала определение (макситмально просто):

Полиморфизм - переопределение методов базового класса дочерним. Пример:

class Gun {
	public:
		void shoot() {
			cout << "bang!" << endl;
		}
};

class M4 : public Gun {
	public:
		void shoot() {
			cout << "tra-ta-ta!" << endl;
		}
};

Так же вот:

class Gun {
	public:
		void shoot(int a) {
			cout << "bang!" << a << endl;
		}
};

class M4 : public Gun {
	public:
		void shoot(int a, int b) {
			cout << "tra-ta-ta!" << a + b << endl;
		}
};

То есть мы можем переопределять реализацию методов базового класса. Далее почитай про виртуальные методы и ключевое слово "override" по тегу "#virtual" или "#override".

Говоря о наследовании в плюсах, хотелось бы выделить следующее:

1. Наследование производиться при помощи вот такого синтаксиса:

class B : A {

}

P.S. в данном случае класс "B" наследуется от класса "А".

2. При наследовании стоит указывать модификатор доступа:

class B : public A {

}

Что это значит? Это значит то, что при выставлении определённого модификатора доступа, наследуемые атрибуты класса родительского "A", а точнее их модификаторы, притерпят некоторые изменения. Вот отличная таблица:

----------------------------------------------------------
				| Исходный модификатор доступа  	 |
----------------------------------------------------------
				| public	| private	| protected	 |
----------------------------------------------------------
public-наследование    | public	| private	| protected  |
----------------------------------------------------------
private-наследование   | private | private	| private    |
----------------------------------------------------------
protected-наследование | protected | private | protected |

То есть от модификатора доступа наследования зависит последующий доступ к атрибутам базового класса.

3. Модификатор доступа protected при наследовании становится public для класса наследника, но извне (типа B.protectedAttribute()) ведёт себя как private.

4. При наследовании конструкторы классов вызываются от родителя к наследникам. Пример:

class A {
	A() {
		cout << "constructor A" << endl;
	}
}

class B : A {
	B() {
		cout << "constructor B" << endl;
	}
}

class C : B {
	C() {
		cout << "constructor C" << endl;
	}
}

Если мы создадим экземпляр класса "C", то при запуске программы увидим в консоли:

constructor A
constructor B
constructor C

Логика такая:

Класс "C" наследуется от класса "B", при этом класс "B" фактически инициализируется внутри класса "C", что означает вызов конструктора класса "B", но когда дело до него доходит, мы видим, что класс "B" наследуется от класса "A", а значит нужно проинициализировать класс "A", прежде чем вызвать конструктор класса "B". Так как класс "A" ни от кого не наследуется - конструктор вызовется сразу, и вот мы видим в консоли "constructor A". Потом, возвращаемся назад к классу "B", который, увидив, что класс "A" готов к работе, вызывает свой конструктор, затем класс "C", так же понимает, что класс "B" готов и запускает уже свой конструктор. Вот такая не хитрая выходит цепочка.

4. Порядок вызовов деструкторов при наследовании обратный, так как он вызывается при уничтожении объектов. А исходя из правила стека - последний созданный объект будет первым уничтожен. Тем самым первым вызовется деструктор Класса "C", потом "B" и наконец "A".

5. Как ты заметил - при наследовании, компилятор вызывает дефолтный конструктор базового класса (в примере выше класса "A"). но, что если нам нужно воспользоваться нашим собственным конструктором, который принимает некие параметры? В таком случае мы можем сами вызвать конструктор базового класса. Чтобы вызвать конструктор базового класса, нам нужно воспользоваться вот такой конструкцией:

class A {
	public:
		A(int i) {
			cout << "constructor with value " << i << endl;
		}
};

class B : A {
	public:
		B():A(5) {

		}
};

Теперь, после создания экземпляра..

int main() {
	B b;

	system("pause > nul");
	return 0;
}

..в консоль выйдет..

constructor with value 5

Таким образом мы можем юзать любые конструкторы базового класса при инициализации наследника.

Классы и ООП в C++ ...

Вообще тема интересная) Для начала давай глянем на основной синтаксис инициализацци класса:

class Human {

};

P.S. ставить в конце класса точку с запятой обязательно.

А вот так мы можем писать различные свойства или методы (свойства принято называть "поля"):

class Human {
	string name = "Alex";
	int age = 32;

	void showInfo() {
		cout << this -> name << endl;
		cout << this -> age << endl;
	}
};

P.S. кстати, this ставить не обязательно. Зачем это делаю я почитай в заметке по тегу "#this".

Теперь давай создадим экземпляр такого класса. В плюсах это делается так:

int main() {
	Human human;

	system("pause > nul");
	return 0;
}

Теперь давай вызовем у него метод showInfo:

int main() {
	Human human;

	human.showInfo();

	system("pause > nul");
	return 0;
}

OOPS! Ты получишь ошибку при попытке получить доступ к атрибуту объекта human. Но почему? Чтобы понять, для начала нам нужно разобраться с модификаторами доступа атрибутов класса:

1. public - атрибут доступен извне;
2. private - атрибут доступен только внутри самого класса и не доступен снаружи (но доступен для дружественных классов и функций);
3. protected - атрибут не доступен извне (но становится доступным внутри класса при наследовании).

P.S. если для какого либо атрибута не указать модификатор свойств, то ему автоматически будет выдан private (поэтому и не мог получить доступ к мтоду showInfo).

Теперь давай реализуем этот класс правильно:

class Human {
	private:
		string name = "Alex";
		int age = 32;

	public:
		void showInfo() {
			cout << name << endl;
			cout << age << endl;
		}
};

Вот теперь, если я сделаю так..

human.showInfo();

..я получу на выход в консоль:

Alex
32

Круто! Теперь мы можем создавать сеттеры (методы для установки данных) или геттеры (методы для получения данных; кстати, наш метод showInfo почти геттер, вот только он ничего не возвращает). Но, как запихать значения для свойств сразу при создании экземпляра? Это называется конструктор, и о нём ты можешь почитать по тегу "#constructor" или "#конструктор".

Агрегация и композиция - типы отношений между классами.

Композицию наступает тогда, когда один класс прочно привязан к другому классу и его существование без этого класса не имеет смысла. Как пример - класс Motor, вложенный в класс Car:

class Car {
	public:
		void drive() {
			this -> motor.drive();
		}

	private:
		class Motor {
			public:
				void drive() {
					cout << "Drive!" << endl;
				}
		};

		Motor motor;
};

В данном примере класс Motor не имеет смысла без класса Car и может быть использован только им, и при ничтожении класса Car, класс Motor так же будет уничтожен. Это наглядный пример композиции.

А что на счёт агрегации? Это фактически противоположность композиции..

Агрегация - состояние класса, при котором он не привязан к другим классам и может быть использован этими классами. Для примера мы создадим класс Paint (краска) и классы Bmw и Tesla:

class Paint {
	public: string getColor() {
		return "red";
	}
};

class Bwm {
	public:
		void setColor() {
			Paint paint;
			this -> color = paint.getColor();
		}

	private:
		string color;
};

class Tesla {
	public:
		void setColor() {
			Paint paint;
			this -> color = paint.getColor();
		}

	private:
		string color;
};

В данном примере класс Paint является своего рода универсальным, ведь с его помощью мы можем покрасить не только машины Bmw и Tesla, но и любую поверхность. Такой класс не зависит от других и может быть всеми использован. Это яркий пример агрегации.

Мы можем создавать массивы из наших пользовательских данных, то бишь классов. Для примера мы напишем класс для ботов, который будет иметь свойства "x" и "y" и пару методов:

class Bot {
	private:
		int x;
		int y;

	public:
		Bot(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
};

Отлично, это класс мега простой, поэтому не думаю, что мне стоит что-то объяснять. Сразу приступим к реализации массива ботов:

int main() {
	const int size = 5;
	Bot bots[size];

	system("pause > nul");
	return 0;
}

Как ты видишь, создание массива объектов идентично тому, как если бы мы создавали обычный массив целочисленных значений. Так вот, код выше не будет работать, потому, что когда мы инициализируем массив (в нашем случае на 5 элементов), фактически в памяти создаются экземпляры данного класса, но они ничего не передают в конструктор. Код выше будет эквивалентен:

int main() {
	Bot bots[5]{
		Bot bot;
		Bot bot;
		Bot bot;
		Bot bot;
		Bot bot;
	};

	system("pause > nul");
	return 0;
}

Как видишь, нам для такого случая необходимо создат конструктор, который ничего не будет принимать на вход:

class Bot {
	private:
		int x;
		int y;

	public:
		Bot() {
			this -> x = 0;
			this -> y = 0;
		}

		Bot(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
};

Таким образом наш код отлично скомпилируется. Теперь мы можем заполнить такой массив ботами с нужными координатами:

int main() {
	const int size = 5;
	Bot bots[size];

	for (int i = 0; i < size; ++i) {
		Bot bot(rand() % 120, rand() % 40);
		bots[i] = bot;
	}

	system("pause > nul");
	return 0;
}

P.S. на вход конструктору, в качестве значения "x", я выставил рандомное число от 0 до 120 (символьная ширина консоли), получив остаток от деления "рандомного" числа на 120. То же и со значением "y".

Теперь наш массив содержит в качестве элементов экземпляры нашего класса Bot с рандомными координатами. Этот трюк можно использовать при создании игр или при работе со списками пользователей и тд.

Если мы имеем какой либо не очень большой класс, который мы намерены использовать лишь внутри другого класса, то такой класс мы можем написать внутри того класса, в котором он будет использоваться:

class Image {
	private:
		class Pixel {
			private:
				int r;
				int g;
				int b;

			public:
				PX(int r, int g, int b) {
					this -> r = r;
					this -> g = g;
					this -> b = b;
				}
		};

		string image;
};

Класс, находящийся внутри другого класса, называется внутренний класс, или - "inner class", а тот класс, в который мы вкладываем другой класс - объемлющий класс.

Мы объявляем внутренний класс как абсолютно обычный класс, но доступ к нему извне будет напрямую зависеть от модификатора доступа. Кроме того, доступ к нему извне должен осуществляться с префиксом самого класса:

Image::Pixel px(23, 34, 23);

P.S. это будет работать только если внутренний класс будет иметь модификатор доступа public.

Типо того. Опять же, подобную конструкцию мы собираем в тех случаях, когда этим самым внутренним классом будет пользоваться только класс, который мы собираемся сделать объемлющим. Иначе это не будет иметь смысла. Пример выше отлично подходит под это условие.

static - модификатор атрибутов класса, предназначенный для хранения каких либо данных, общих для всех экземпляров этого класса. То есть, свойство или метод, имеющий перед собой ключевое слово static, будет буквально общим для всех объектов, которые когда либо будут созданы, и при его изменении через один объект или через сам класс, она изменится во всех объектах. Пример:

class Man {
	private:
		string name;
		int age;
		int id;

	public:
		// static property
		static int idCount;

		Man(string name, int age) {
			this -> name = name;
			this -> age = age;
		}
};

int main() {
	Man man("Zerdicorp", 18);

	system("pause > nul");
	return 0;
}

Но, если сейчас мы попытаемся скомпилировать программу - мы словим ошибку, говоряшую о том, что нам необходимо инициализировать статическую переменную idCount. Но разве мы этого не сделали? Правильный ответ - нет, ведь данное свойство фактически простая переменная, вот только с привязкой к имени класса, а значит её нужно инициализировать вне класса:

class Man {
	private:
		string name;
		int age;
		int id;

	public:
		// static property
		static int idCount;

		Man(string name, int age) {
			this -> name = name;
			this -> age = age;
		}
};

// initialize static property
int Man::idCount = 0;

int main() {
	Man man("Zerdicorp", 18);

	system("pause > nul");
	return 0;
}

Теперь всё сработает отлично. Давай проверим:

cout << man.idCount << endl; // 0

Но можно и так:

cout << Man::idCount << endl; // 0

Ибо эта переменная общая для всего класса.

Теперь давай увидим вообще суть статических переменных:

int main() {
	Man man("Zerdicorp", 18);
	Man man2("Alex", 17);

	cout << man.idCount << endl; // 0
	cout << man2.idCount << endl; // 0

	Man::idCount = 133;

	cout << man.idCount << endl; // 133
	cout << man2.idCount << endl; // 133

	system("pause > nul");
	return 0;
}

Теперь думаю всё предельно ясно. Статические свойства мы так же спокойно можем менять и в методах класса, эффект от этого не изменится. Но давай поговорим о практическом применении подобных статических свойств.. один из вариантов - идентификация объектов класса. То есть, проще говоря, каждый объект, при создании, будет получать уникальный id. Вот простейшая реализация:

class Man {
	private:
		string name;
		int age;
		int id;

	public:
		// static property
		static int idCount;

		Man(string name, int age) {
			this -> name = name;
			this -> age = age;
			this -> id = this -> idCount;
			this -> idCount++;
		}

		int getID() {
			return this -> id;
		}
};

int Man::idCount = 0;

int main() {
	Man man("Zerdicorp", 18);
	Man man2("Alex", 17);
	Man man3("James", 22);

	cout << man.getID() << endl; // 0
	cout << man2.getID() << endl; // 1
	cout << man3.getID() << endl; // 2

	system("pause > nul");
	return 0;
}

Мы просто в конструкторе класса Man присваиваем свойству id значение статического свойства idCount, после чего инкрементируем idCount. Получается что поле id следующего созданного объекта получит из idCount значение 1 (ибо idCount инициализирован был со значением 0), после чего он так же делает инкремент. Все последующие созданные объекты повторят эти действия, тем самым, свойство id всегда будет уникальным. Так же существуют другие варианты применения, но о них ты узнаешь по ходу развития.

Теперь давай рассмотрим статические методы класса (да-да, и такие есть). Создание статических методов отличается от обычных методов только модификатором static. Давай сделаем наше поле idCount приватным и напишем для него геттер:

class Man {
	private:
		string name;
		int age;
		int id;
		static int idCount;

	public:
		Man(string name, int age) {
			this -> name = name;
			this -> age = age;
			this -> id = this -> idCount;
			this -> idCount++;
		}

		static int getStatic() {
			return idCount;
		}
};

Теперь обсудим, почему нужно делать этот метод статическим.. Всё дело в доступе. Ведь к такому методу мы можем получить доступ непосредственно от имени самого класса, не обращаясь к экзмеплярам класса (а так же можно вообще их не создавать, от этого переменная всё равно будет доступна):

Man::getStatic(); // 0

Ну а сейчас пару слов об особенностях:

1. Статические методы не имеют доступа к текущему объекту, то есть внутри такого метода не работает слово this, и это логично, ведь статический метод мы можем вызвать при отсутствии эзкемпляров класса вовсе (проще говоря это как обычная функция, только с привязкой к имени класса, но при этом доступ к ней есть так же через экзмепляры).

2. Статические методы, как ты уже заметил, не нужно инициализировать отдельно, как статические свойства, достаточно просто указать модификатор static.

И как финал темы дружественности (ВАХАХАХХА), мы посмотрим на такую вещь, как "дружественные классы". Фактически, это то же самое, что и дружественные методы, вот только мы даём доступ к приват свойствам не только одному конкретному методу, а всем методам класса. Записывается довольно просто и логично:

P.S. не забудь написать прототип класса, который будешь делать дружественным, чут выше класса, который принимает дружбу.

class INC;

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

	// FRIENDSHIIIIP *.*
	friend INC;
};

class INC {
	public: void incx(Point &obj) {
		obj.x++;
	}
};

Теперь мы можем получить доступ к любым скрытым свойствам класса Point из методов класса INC.

Кроме дружественных функций мы можем делать дружественными методы классов. То есть, мы, в методе одного объекта, сможем получить доступ к private или protected свойствам другого объекта. Но подобная конструкция будет чуть сложнее из-за отличительного свойства C++ компилятора, который не видит класс, если он был инициализирован ниже обращения к нему. Кароче, меньше слов:

P.S. чтобы понять некоторые вещи, которые будут происходить ниже, ты должен знать, что такое прототипы, а так же - как выносить методы класса за его пределы (на обе темы есть заметки в этом гигере).

class INC {
	public: void incx(Point &obj) {
		obj.x++;
	}
};

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

	friend void INC::incx(Point &obj);
};

с одной стороны всё сделано правильно, вот только наш люимый компилятор ругнётся на то, что класс Point, который мы указали в принимаемых параметрах метода incx класса INC, не найден. Всё потому, что его инициализация находится ниже в коде. Чтобы решить данную проблему нужно написать прототип класса Point в начале кода:

class Point;

class INC {
	public: void incx(Point &obj) {
		obj.x++;
	}
};

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

	friend void INC::incx(Point &obj);
};

Ошибка исчезла. Вот только на её место встала ещё одна - мы не можем получить доступ к свойству "x" у приходящего объекта obj в метоже incx. Эта ошибка выходит потому, что, хоть класс и инициализирован, он всё ещё не заполнен какими либо свойствами или методами. Чтобы решить уже данную проблему, мы должны вынести метод incx за пределы класса INC, а если быть точнее - ниже класса Point:

P.S. при выносе метода из класса не забываем оставить в самом классе прототип этого метода.

class Point;

class INC {
	public: void incx(Point &obj);
};

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

	friend void INC::incx(Point &obj);
};

void INC::incx(Point &obj) {
	obj.x++;
}

Такой вариант уже будет отлично работать:

int main() {
	Point p(15, 13);
	INC inc;

	// p.x = 15
	inc.incx(p);
	// p.x = 16

	system("pause > nul");
	return 0;
}

Работая с лкассами, может появится желание получить из какой либо обычной функции (не метода) значение private или protected свойств класса. Что-то типо того:

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
};

void test(Point &obj) {
	obj.x = 333;
	obj.y = -333;
}

int main() {
	Point p(15, 13);

	test(p);

	system("pause > nul");
	return 0;
}

Тут мы просто создали класс Point, определили приватные свойства и конструктор. Так же мы имеем функцию test, которая на вход принимает ссылку на объект типа Point и далее пытается изменить поля x и y этого объекта. В main мы создаём экземпляр класса Point - "p", передавая инициализирующие значения 15 и 13 в конструктор, после чего вызываем функцию test, передавая в качестве параметра объект "p". 

И да - это даст нам ошибку, говорящую о том, что мы не можем получить доступ к private полям класса Point. Где же мы пытаемся совершить такой злостный грех? Именно. Ведь всем известно, что получить доступ в приватным и защищённым полям вне класса нельзя. Но мы хотим! Что же делать? Ммм, а может подружить класс и функцию? ХА, отличная мысль :D

Но как нам это сделать? Это не сложно.. всего-то нужно написать прототип функции в самом классе с пометкой friend.. и это я сейчас не шучу :-]

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

	// friendship is MAGIC!
	friend void test(Point &obj);
};

void test(Point &obj) {
	obj.x = 333;
	obj.y = -333;
}

int main() {
	Point p(15, 13);

	test(p);

	system("pause > nul");
	return 0;
}

Та-дааам, и всё работает! Теперь у тебя не возникнет вопроса, почему дружба - магия?)

P.S. если ты не помнишь, что такое прототип функции, то можешь глянуть короткую заметку по тегу "#prototype" или "#прототип".

Мы можем выносить методы, конструкторы и деструкторы класса за пределы его фигурных скобок. Для этого необходимо написать прототип такого метода в самом классе, а далее сделать вот что:

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

		void test();
};

void Point::test() {
	this -> x = 333;
	this -> y = -333;
}

Если бы метод test что-то возвращал, нужно было бы void заменить на тип возвращаемого значения, соответственно. 

Так довольно удобно выносить за пределы класса конструкторы и деструкторы:

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y);
		~Point();
};

Point::Point(int x, int y) {
	this -> x = x;
	this -> y = y;
}

Point::~Point() {
	cout << "Calling destructor" << endl;
}

P.S. главное не забыть прописать в классе прототип данного метода.

В C++ существует некое понятие "прототипа". Звучит оно довольно круто и кажется чем-то умным и сложным, но по факту всё очень просто. 

Прототип - преинициализация объекта; написание функции или класса без фигурных скобок.

Вот пример:

// this is prototype
void test();

void test() {
	cout << "This is function!" << endl;
}

Ну и ещё вот:

// and this is prototype
class Point;

class Point {
	private:
		int x;
		int y;

	public:
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
}

Зачем это нужно. Ну, например, когда функция инициализирована ниже той функции, в которой её вызывают:

void callTest() {
	test(); // ERROR
}

void test() {
	cout << "This is function!" << endl;
}

Такая запись выведен ошибку о том, что функция test() не найдена в данном поле видимости (то есть её как бы нету). Всё потому, что инициализация идёт последовательно построчно, а значит функции, инициализированные ниже их вызова, будут ломать программу. Для решения такой проблемы используют прототипы:

void test();

void callTest() {
	test(); // SUCCESS CALL TEST
}

void test() {
	cout << "This is function!" << endl;
}

P.S. если функция принимает какие-то параметры, то в прототипе так же обязательно их указывать:

void test(int value);

void test(int value) {
	cout << "This is function! " << value << endl;
}

Всё, что делает прототип - сообщает компилятору о том, что где то в коде обязательно будет присутствовать подобная функция или класс, что даёт компилятору основания не ругаться (ведь мы, фактически, просто инициализируем функцию в начале кода). На маленьких проектах это всё не обязательно, ведь совсем не сложно переместить функцию чуть выше по коду. Но в больших.. там история совсем другая, ведь заботиться о перестановке всех функций и классов в порядке их вызова - тот ещё пи*ец, так что..

Так же прототипы используются для указания дружественных классов, но об этом можешь почитать по тегу "#friend" в гигере "ООП".

Если ты слышал о понятии "перегрузка", то данная фича, присутствующая в пользовательских типах данных (то бишь классах), очень тебе понравится. 

Фактически, название заметки говорит само за себя - мы будем перегружать различные операторы (то есть создавать отличные от стандартных реализации неких функций). Но, для начала, чтобы лучше понимать, как всё это работает, смотри:

int a;
int b = 6;

a = b;

Что ты видишь? Ну, переменной "а" мы присвоили значение переменной "b". А ты не задумывался что значит вот этот магический знак "равно" и как он работает. Чтобы понять, давай для начала создадим свой класс, который будет аналогией типу int (очень кривой, чисто для примера):

class INT {
	public:
		int value;

		INT(int value) {
			this -> value = value;
		}
};

Вот класс INT, который имеет одно публичное поле value и обычный конструктор, который принимает какое либо интовое значение, далее он присваивает его своему свойству value. Теперь давай создадим пару экземпляров этого класса:

int main() {
	INT a(5);
	INT b(10);

	system("pause > nul");
	return 0;
}

P.S. что тут произошло, надеюсь, объяснять не нужно.

Теперь смотри.. если мы захотим присвоить значение value одного объекта другому то логично будет сделать так:

a.value = b.value;

И это будет работать. Но, мы можем сделать и так:

a = b;

Дефолтная реализация оператора присваивания возьмёт поля из объекта "b" и происвоит их объекту "a". Происходит примерно это:

a.value = b.value;

Если бы полей было больше - произошло бы присваивание их всех, к примеру:

a.value = b.value;
a.count = b.count;
a.name = b.name;

и т.п.

И всё прекрасно. Но.. что, если наш класс будет не столь простым. К примеру, наш класс INT будет хранить не просто одно интовое значение value, а динамический массив int-ов. Ну, давай посмотрим:

class INT {
	private:
		int *values;
		int size;

	public:
		INT(int size) {
			this -> size = size;
			this -> values = new int[size];

			for (int i = 0; i < size; ++i) {
				this -> values[i] = rand() % 100;
			}
		}

		~INT() {
			cout << "Destructor " << this << endl;
			delete[] this -> values;
		}
};

Выше мы изменили обычную интовую переменную value на указатель values, так же обавили поле size. Далее в конструкторе мы приняли интеджер size и на его основе присвоили указателю values массив интов на кол-во элементов size. После заполнили его рандомными значениями. Так же мы имеем деструктор, который просто освобождает место в оперативке, которое занимал динамический массив values. И так, давай теперь сделаем наше присваивание:

int main() {
	INT a(5);
	INT b(10);

	a = b;

	system("pause > nul");
	return 0;
}

Что же мы получим? Ну, начнём с банального - переменная size объекта "b". Её значение без проблем получит переменная size объекта "a". Но что с указателем values? С ним, как раз таки, не всё так гладко. Если ты хорошо знаешь указатели, то ты понимаешь, что будет, если присвоить указатель указателю (мы просто получим два указателя, которые будут указывать на один и тот же объект в оперативке). Исходя из этой логики мы можем предсказать следующие проблемы:

1. Утечка памяти, связанная с тем, что место в оперативке, занимаемое массивом values объекта "a" не будет освобождено, так как указатель values будет указывать на массив объекта "b", из чего собственно вытекает вторая проблема..

2. Так как объект "а" был создан раньше - деструктор объекта "b" сработает первым, а значит место, занимаемое массивом vаlues уже будет освобождено. Исходя из того факта, что переменная values объекта "a" является указателем на тот же участок памяти, что и указатель values объекта "b", во время вызова деструктора объекта "a" будет совершена попытка удаления того участка памяти, что уже был освобождён деструктором объекта "b". Это может вызвать ошибку программы, ведь пытаться очищать не свои участки памяти ой как плохо. 

Смотря на все эти проблемы становится понятно, зачем нужно создавать перегрузки для различных операторов, и сейчас давай реализуем перегрузку для оператора присваивания. Но, для начала узнаем, что вообще такое операторы на самом деле:  

Операторы - обычные методы классов, с одной исключительной чертой: ключевым словом operator и знаком самого оператора (например =). Давай напишем один такой метод для нашего класса INT:

class INT {
	private:
		int *values;
		int size;

	public:
		INT(int size) {
			this -> size = size;
			this -> values = new int[size];

			for (int i = 0; i < size; ++i) {
				this -> values[i] = rand() % 100;
			}
		}

		~INT() {
			cout << "Destructor " << this << endl;
			delete[] this -> values;
		}

		void operator = (const INT &obj) {
			this -> size = obj.size;

			delete[] this -> values;

			this -> values = new int[obj.size];

			for (int i = 0; i < obj.size; ++i) {
				this -> values[i] = obj.values[i];
			}
		}
};

P.S. заметь, тип нашего метода - void, и это не совсем верно, я в итоге объясню, почему.

Давай разберёмся:

1. operator - ключевое слово, говорящее компилятору о том, что дальше последует знак какого либо оператора (довольно логично);
2. " = " - сам оператор, для которого мы пишем перегрузку.

Что же мы имеем на вход? Да то же самое, что обычно принимаем на вход конструктора копирования - константную ссылку на объект типа INT. Константа нужна для того, чтобы мы не могли испортить объект, а ссылка - чтобы нам не получать объект по значению (передача по значению будет значить копирование исходного объекта и его локальное воссаздание в переменной obj, а значит и лишняя трата памяти, а ведь нам нужны лишь некоторые данные из прихоядщего объекта). В самом методе мы:

1. Присваиваем нашему свойству size значение size у приходящего объекта,;
2. Освобождаем участок памяти, ранее занятый массивом values (чтобы создать новый массив, идентичный массиву values копируемого объекта);
3. Собственно создаём новый динамический массив, кол-во элементов которого определяем свойством size у копируемого объекта;
4. Заполняем элементы созданного массива элементами массива копируемого объекта. 

Ну вот в принципе и всё. Мы скопировали объект правильно, без утечки памяти и прочих проблем. Но, создавать подобные перегрузки, как ты уже понял, стоит лишь в том случае, когда идёт какая-либо работа с указателями и объектами, типа динамического массива.

Ну а теперь давай присвоим объекту "а" объект "b":

int main() {
	INT a(5);
	INT b(10);

	a = b;

	system("pause > nul");
	return 0;
}

Наш метод отработает и объект "a" будет иметь массив values, абсолютно идентичный массиву values объекта "b", но с другим адресом, ествественно.

Теперь давай немного поговорим о записи оператором и о том, как это понимает компилятор. Вот, например, наш метод оператора присваивания можно записать и так:

a.operator=(b);

Компилятору всё равно. Ведь как я говорил ранее - все операторы - методы; в нашем случае, просто функция, вызванная у объекта "a", в которую мы на вход передали объект "b".

Давай-ка теперь поговорим об одной интересной проблеме, но для начала глянь на это:

int main() {
	INT a(5);
	INT b(7);
	INT с(13);

	a = b = с;

	system("pause > nul");
	return 0;
}

Знакомая конструкция? А ты знаешь, что она работать не будет? А почему догадываешься? Если нет, то посмотри (даже если да, ты вынужден посмотреть, ахах):

a.operator=(b.operator=(c));

Так, тебе, думаю, будет понятнее, о чём речь.. конечно же вся проблема в типе void, который имеет наша перегрузка оператора присваивания, ведь данный тип ничего не возвращает, а значит после отрабатывания оператора присваивания у объекта b произойдёт вот это:

a.operator=(НИ ХУ Я); // ERROR ERROR ERROR THIS IS VOID ERROR

Ахах. Чтобы решить эту проблему мы должны, во первых, заменить тип void на что-то дргое, а, во вторых, понять цепочку событий, что поможет решить первую задачку. Раз метод оператора присваивания принимает на вход объект типа INT, и его результат мы хотим возвратить на вход ещё одному оператору присваивания (у объекта "a"), то будет довольно логично сделать тип возвращаемого значения нашего метода такой же, как и у принимаегого параметра, то есть INT. Кроме того, мы должны возвращать ссылку, а не сам объект (после типа ставим амперсант):

public: INT & operator = (const INT &obj) {
	/* code */
}

Оооокей, а что же нам нужно возвращать? Понятное дело, объект типа INT, но какой именно - приходящий объект obj или текущий объект - this? Давай думать логически. Мы же передаём на вход оператора присваивания объекта "a" не объект "c", а результат выполнения оператора присваивания объекта "b", а значит будет чуть логичнее возвращать именно изменённый объект "b":

public: INT & operator = (const INT &obj) {
	/* code */

	return this;
}

Но, выйдет ошибка, ведь, если ты не забыл, this - просто указатель, а значит, чтобы передать сам объект, нам нужно этот указатель разименовать. Ещё не забыл, что это?) Тогда вперёд:

public: INT & operator = (const INT &obj) {
	/* code */

	return *this;
}

Теперь всё просто супер! Мы можем выполнить следующую операцию..

a = b = с;

..и в наших объектах "a" и "b" свойство size благопалучно получат значение 13 (ибо объект "c" имел именно такое значение для поля size), а динамические массивы values обоих объектов будут полностью идентичны массиву values объекта "c".

Ну вот и всё. Фактически, с этими знаниями можно выполнять перегрузки для любых операторов, будь то оператор деления "/", или оператор равенства "==" (да даже неравенства "!=").

Существует ещё так называемый конструктор копирования. Он предназначен для создания объекта по подобию другого объекта. Записывается он так:

Point p(12, 54);
Point p2(p);

В данном случае мы создаём объект p и пихаем в его конструктор значения 12 и 54. После этого мы создаём ещё один объект p2 и в качестве параметра конструктора передаём предыдущий объект p. Но как это? Да это элементарно.. класс Point просто имеет по дефолту перерузку для своего конструктора, которая на вход принимает объект типа Point. Ну и как бы всё отлично, ведь теперь, если мы сделаем..

print(p2.x);

..мы на выход получим 12, собственно, как и у объекта p. Но в чём же заключается подвох при использовании дефолтного конструктора копирования? Для понимания этого, мне нужно привести пример..

Предположим, у нас имеется класс Test:

class Test {
	public:
		int* data;
		int size;

		Test(int size) {
			this -> size = size;
			this -> data = new int[size];

			for (int i = 0; i < size; ++i) {
				this -> data[i] = rand() % 100;
			}
		}

		~Test() {
			delete[] this -> data;
		}
};

Класс имеет два поля - указатель data и переменная size. В конструкторе мы принимает значение size и создаём на его основе массив в динамической памяти, который присваиваем указателю data. Так же мы имеем деструктор, который, непосредственно, освобождает динамическую память, прежде занятую массивом data. Теперь давай создадим один такой объект:

int main(int argc, char* argv[]) {
	Test test(10);

	system("pause > nul");
	return 0;
}

То есть у нас имеется объект test, у которого есть свойство data - указатель на массив в динамической памяти. Отлично. Сейчас давай скопируем его в новый объект test2:

int main(int argc, char* argv[]) {
	Test test(10);
	Test test2(test);

	system("pause > nul");
	return 0;
}

Теперь давай вместе подумаем, почему такая конструкция будет работать некорректно? Дам подсказку - тут замешен указатель data :D Короче говоря, после выхода из функции main у нас в обоих объектах срабатывает деструктор. Но это происходит не одновременно, а в обратном порядке: последний созданный объект будет первым удаляться (правило стэка). Тем самым, первым сработает деструктор у объекта test2 и массив по адресу, на который указывает указатель data, будет освобождён. Но вот в чем подкол.. конструктор копирования, благодаря которому мы создали объект test2 по подобию объекта test, произвёл прямое копирование, то есть, вместо полного копирования массива data, он скопировал указатель на тот самый массив. То есть получается у нас для двух указателей двух объектов имеется один массив в оперативке. Это чревато тем, что, очистив массив в деструкторе объекта test2, мы далее попытаемся снова очистить тот участок памяти в деструкторе объекта test, но память в том месте уже нам не пренадлежит, ведь мы её очистили ранее. Если ты понял проблему - поздравляю!) Чтобы её решить, мы должны сами создать свой конструктор копирования и реализовать там корректное копирование динамического массива (чем мы уже занимались однажды). Для начала определимся с тем, как выглядит конструктор копирование. Фактически, опять же, это просто перегрузка обычного конструктора, принимающая в качестве параметра объект типа Test (а точнее ссылку на этот объект). А вот теперь гляди на полную реализацию корректного копирование:

class Test {
	public:
		int* data;
		int size;

		Test(int size) {
			this -> size = size;
			this -> data = new int[size];

			for (int i = 0; i < size; ++i) {
				this -> data[i] = rand() % 100;
			}
		}

		// конструктор копирования
		Test(const Test &obj) {
			this -> size = obj.size;
			this -> data = new int[obj.size];

			for (int i = 0; i < obj.size; ++i) {
				this -> data[i] = obj.data[i];
			}
		}

		~Test() {
			delete[] this -> data;
		}
};

P.S. обрати внимание на принимаемые параметры конструктора копирования, тебе должно быть предельно ясно, что есть что (если нет - мне тебя жалко, ведь это просто константная переменная типа Test, являющаяся ссылкой на передаваемый объект).

Первым делом мы устанавливаем свойство size, ведь производя копирование какого либо объекта, в создаваемом объекте мы обходим стороной обычный конструктор, тем самым, не установив size, мы не усмеем произвести повтороное копирование созданного объекта, ведь переменная size будет иметь мусор. И так, далее мы создаём новый массив в динамической памяти, длину которого устанавливаем, очевидно, по длине массива (свойство size) у копируемого объекта. После чего мы просто итерируемся в цикле for size раз и данные из массива копируемого объекта присваиваем массиву нового объекта. Всё довольно просто и примитивно. Таким образом, если во время срабатывания деструктора мы выведем на экран указатель data, то мы увидим различные адреса (например, 0x75cd32 и 0x75cc82), а значит очистка массива в одном объекте не полвлияет на массив другого.

Когда ты слышишь слово "конструктор", тебе не приходит в голову, что должна быть некая противоположность? Хах, она и правда есть:

Деструктор - метод класса, который будет вызван во время удаления экземпляра класса; предназначен для того, чтобы можно было более корректно завершить жизненный цикл объекта (например, если объект использует динамическую память в своих свойствах).

P.S. если ты почувствовал аналогию с "componentWillUnmount" из React-а, то ты, фактически, прав!)

Деструктор записывается аналогично конструктору, за исключением одного спец знака - "~", который пишется перед именем деструктора:

class Point {
	public: 
		int x;
		int y;

		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}

		~Point() {
			print("Point was destroyed..");
		}
};

Теперь вопрос, в каком же случае объект уничтожается? Ну, один из самых явных примеров - когда выполнение программы покидает какую либо область видимости (фигурные скобки). Вот пример:

void initPoint() {
	Point p(300, 200);
}

int main(int argc, char* argv[]) {
	initPoint();

	system("pause > nul");
	return 0;
}

Как только функция initPoint отработает и программа продолжит своё выполнение в функции main (выполнение будет смещаться вниз, к "system("pause > nul");"), то наш объект "p" будет уничтожен, тем самым мы увидем на экране запись:

Point was destroyed..

..сразу при старте программы.

Опять же, деструктором обычно пользуются тогда, когда объект, в качестве какого либо из свойств, имеет указатель на динамическую память, например, динамический массив. Таким образом, освободив динамическую ячейку памяти перед непосредственным удалением объекта "p", мы избежим утечки памяти.

Давай посмотрим, каким образом нам сделать конструктор класса (вспомни __init__ в питоне). В качестве конструктора мы будем использовать вот такую конструкцию:

class Human {
	private: 
		string name;
		int age;

	public: void init(string name, int age) {
		this -> name = name;
		this -> age = age;
	}
}

P.S. для обращения к свойствам класса из другого модификатора доступа нам необходимо указать конструкцию: this -> property;

P.S.S. первоначальные свойства класса принято делать приватными.

То есть мы имеем какие то свойства класса и функцию init, которую остаётся вызвать, передав соответствующие аругменты:

int main(int argc, char* argv[]) {
	Human human;

	human.init("ZERDICORP", 18);

	system("pause > nul");
	return 0;
}

P.S. для создания экземпляра класса мы пишем: Classname variable; Переменную принято называть именем класса с маленькой буквы: Human human;

Теперь давай создадим метод, для получения данных:

class Human {
	private: 
		string name;
		int age;

	public: void init(string name, int age) {
		this -> name = name;
		this -> age = age;
	}

	public: string getInfo() {
		return "Name: " + this -> name + "\nAge: " + to_string(this -> age);
	}
}

Но можно и так:

class Human {
	private: 
		string name;
		int age;

	public:
		void init(string name, int age) {
			this -> name = name;
			this -> age = age;
		}

		string getInfo() {
			return "Name: " + this -> name + "\nAge: " + to_string(this -> age);
		}
}

Остаётся сделать:

cout << human.getInfo() << endl;

// Name: ZERDICORP
// Age: 18

Сейчас мы написали свой простейший конструктор, но классы, на самом деле, имеют свою встроенную реализацию конструкторы. Такой конструктор записывается как функция, имеющая имя класса, но не имеющая никакого типа. Вот пример:

class Point {
	public: 
		int x;
		int y;

		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
};

P.S. конструктор обязательно должен иметь имя класса, так же он не имеет никакого типа, даже void-а.

То есть, это практически то же самое, что и наша функция init, но более естественно и удобно. 

Для того, чтобы передать в данный конструктор какие либо параметры, мы должны чуть иначе инициализировать экземпляр класса, а именно:

int main(int argc, char* argv[]) {
	Point p(300, 200);

	system("pause > nul");
	return 0;
}

Ну ведь круче, не правда ли? Вообще, даже если мы не напишем конструктор класса, компилятор создаст конструктор по умолчанию, вот только такой конструктор не будет нуждаться в параметрах, отчего мы можем инициализировать экземпляр без скобок вообще: 

Point p;

Ну, собственно как в примерах с классом Human.

Ещё я бы хотел рассказать о такой штуке, как перегрузка конструктора класса (если не знаешь, что такое перегрузка, то почитай заметку по тегу "#overload" или "#перегрузка"). То есть, мы можем создавать несколько конструкторов, различных по принимаемым параметрам и их работе. Вот пример, чтобы без лишних слов:

class Point {
	public: 
		int x;
		int y;
		int z;

		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
			this -> z = NULL;
		}

		Point(int x, int y, int z) {
			this -> x = x;
			this -> y = y;
			this -> z = z;
		}
};

Для чего же это нужно? Давай представим такую ситуацию.. ты делаешь игру, и в ней есть два режима - 2D и 3D. За многие точки в игровом пространстве отвечает класс Point. Так вот, если игрок выбирает режим 2D, то экзмепляр класса Point должен будет инициализировать лишь координаты x и y, а если 3D - x, y, и z, соответственно. В таком случае мы можем создать два конструктора: первый будет инициализироваться только с параметрами x и y, а второй с x, y, z. Таким образом мы можем сделать что-то типо того:

int main(int argc, char* argv[]) {
	string mode = "3D"; 

	if (mode == "3D") Point p(300, 200, 34);
	else if (mode == "2D") Point p(300, 200);

	system("pause > nul");
	return 0;
}

Думаю суть перегрузки понятна.

Надо сказать пару слов о this.. 

class Point {
	private:
		int x;
		int y;

	public:
		// конструктор
		Point(int x, int y) {
			this -> x = x;
			this -> y = y;
		}
}

В первую очередь - это указатель, а именно - указатель на тот объект, который мы проинициализировали как экземепляр класса (в нашем случае - объект "p"). На самом деле, в примере выше, мы можем вообще не ставить этот указатель, ведь компилятор сам его добавит. Но зачем тогда он? Во первых - для избежания совпадения имён параметров методов и свойств объекта, в качестве примера, вот конструктор без ключевого слова this:

Point(int x, int y) {
	x = x;
	y = y;
}

P.S. то есть, в этом примере мы присваиваем значение приходящего параметра x самому себе, в то время как свойство x объекта Point не меняется никоим образом. Аналогично с y.

..во вторых - для лучшей ориентации по коду, ведь, в больших проектах не очень то и просто отличить, какая переменная временная, а какая является свойством объекта, что приводит ко многим неудобствам, заблуждениям и говнокоду. Думаю ты меня понял :D

Давай сразу с определения:

Перегрузка - создание нескольких функций, одинаковых по названию, но различных по принимаемым параметрам.

Да, вот так всё просто. А вот и пример:

int sum(int a, int b) {
	return a + b;
}

int sum(int a, int b, int c) {
	return a + b + c;
}

int main() {
	cout << sum(4, 4) << endl; // 8
	cout << sum(4, 4, 4) << endl; // 12

	system("pause > nul");
	return 0;
}

Но как это работает? Двольно таки просто. Всё дело в компиляторе, который смотрит не только на название функции, но и на принимаемые параметры. Если у нас две реализации функций sum, то при попытке вызова одной из них компилятор запустит ту, к которой переданные на вход данные больше всего подходят. Таким образом принимаемые параметры могут отличаться даже типами:

int sum(int a, int b) {
	return a + b;
}

string sum(string a, string b) {
	return a + b;
}

int main() {
	cout << sum(4, 4) << endl; // 8
	cout << sum("Hello, ", "world!") << endl; // Hello, world!

	system("pause > nul");
	return 0;
}

Принцип перегрузки часто используется в ООП, так что усвоить и понять его довольно таки важно. Но думаю у тебя не возникнет проблем с пониманием :3

На самом деле это даже не тема для спора. Если объянсить кратко, то вот:

Функция main должна быть типа int для того, чтобы возвращать какое либо значение тому объекту, который её вызвал.

Что я под этим подразумеваю? Ну, смотри.. представим программу "test.exe". И вот мы запускаем её из cmd. Программа вывела какие-то данные и завершила работу. В момент завершения, условно, наш виндовс, за счёт..

return 0;

..получил от неё код 0 - то есть всё хорошо отработало и ошибок совершено не было. То есть возвращая какое либо значение мы сообщаем вызвавшему нас объекту, что всё отработало корректно и работа прекратилась. Такая запись:

int main() {

	return 0;
}

..является стандартом и считается более верным решением, чем void, который не возвращает ничего.

На самом деле, функция main, которая является точкой входа в программу, принимает некоторые параметры, а точнее:

"int argc" и "char* argv[]"

Но что это? Простыми словами - это те параметры, с которыми мы запускаем нашу прогу. Ну, думаю ты видел в фильмах, и может даже сам хотел сделать в консоли так:

programm.exe --hack --hash_password

Ну, думаю ты понял о чем я )) Это те самые параметры, которые мы часто используем, например в npm или pip ) 

Теперь разберём параметры:

1. argc - кол-во параметров (никогда не бывает меньше 1);
2. argv - указатель на массив строк, содержащий наши параметры.

Теперь смотри. Можно сделать так:

int main(int argc, char* argv[]) {
	for (int i = 0; i < argc; ++i) {
		cout << argv[i]) << endl;
	}

	system("pause > nul");
	return 0;
}

Таким образом мы итерируемся по массиву парметров и выводим их в консоль. Если сейчас запустить такую прогу в cmd, то на выход мы получим что-то типо того:

programm.exe

Это путь к нашей программе (он может быть и "C:/.../programm.exe", всё зависит от того, откуда мы её запускаем). Путь находится в параметрах по дефолту (кстати, именно поэтому argc не может быть меньше 1).

Если же мы запустим прогу так:

C:/.../dev_dir>programm.exe parameter

То получим:

programm.exe
parameter

Короче, думаю тебе понятна суть этой конструкции ) Пользуйся! 

