Формик, со всеми своими фишками валидации и хранения данных, ещё и поставляет свою собственную форму. Это позволяет нам обойтись без рукотворных input-ов, проверок на ошибку и многой другой рутинной работы. Мы даже сможем обойтись без "getFieldProps()". И так, импортируем все необходимые компоненты:

import { Formik, Form, Field, ErrorMessage } from "fromik"

Теперь напишем форму с новыми компонентами:

const SigninForm = (props) => {
	return (
		<Formik 
			initialValues={{
				login: "",
				password: "",
				rememberMe: false
			}}
			validationSchema={ // Yup }
			onSubmit={(values, {setSubmitting}) => {
				alert(JSON.stringify(values, null, 2))
				setSubmitting(false)
			}}
		>
			{(formik) => {
				return (
					<Form>
						<Field type="login" name="login" placeholder="login" className={css.field} />
						<ErrorMessage name="login" />

						<Field type="password" name="password" placeholder="password" className={css.field} />
						<ErrorMessage name="password" />

						<Field type="checkbox" name="rememberMe" /><span>remember me</span>
						<button 
						type="submit" 
							className={formik.isSubmitting ? css.disabled : css.undisabled} 
							disabled={formik.isSubmitting}
						>sign in</button>
