upstream *hram_nikola_server {
  # fail_timeout=0 means we always retry an upstream even if it failed
  # to return a good HTTP response (in case the Unicorn master nukes a
  # single worker for timing out).

  server unix:/webapps/*hram_nikola/run/gunicorn.sock fail_timeout=0;
}

server {
    listen   80;
    server_name hram-nikola.ru www.hram-nikola.ru;

    client_max_body_size 4G;

    access_log /webapps/*hram_nikola/logs/nginx-access.log;
    error_log /webapps/*hram_nikola/logs/nginx-error.log;

    # css and js
    location /static/ {
        alias   /webapps/*hram_nikola/*church/*Church/static/;
    }

    # images and other media
    location /uploads/ {
        alias   /webapps/*hram_nikola/*church/*Church/uploads/;
    }

    location / {
        # an HTTP header important enough to have its own Wikipedia entry:
        #   http://en.wikipedia.org/wiki/X-Forwarded-For
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # enable this if and only if you use HTTPS, this helps Rack
        # set the proper protocol for doing redirects:
        # proxy_set_header X-Forwarded-Proto https;

        # pass the Host: header from the client right along so redirects
        # can be set properly within the Rack application
        proxy_set_header Host $http_host;

        # we don't want nginx trying to do something clever with
        # redirects, we set the Host: header above already.
        proxy_redirect off;

        # set "proxy_buffering off" *only* for Rainbows! when doing
        # Comet/long-poll stuff.  It's also safe to set if you're
        # using only serving fast clients with Unicorn + nginx.
        # Otherwise you _want_ nginx to buffer responses to slow
        # clients, really.
        # proxy_buffering off;

        # Try to serve static files from nginx, no point in making an
        # *application* server like Unicorn/Rainbows! serve static files.
        if (!-f $request_filename) {
            proxy_pass http://*hram_nikola_server;
            break;
        }
    }

    # Error pages
    error_page 500 502 503 504 /500.html;
    location = /500.html {
        root /webapps/*hram_nikola/static/;
    }
}

# need your server name
upstream hram_nikola_server {
    # fail_timeout=0 means we always retry an upstream even if it failed
    # to return a good HTTP response (in case the Unicorn master nukes a
    # single worker for timing out).

    # need your current path to gunicorn
    server unix:/webapps/hram_nikola/run/gunicorn.sock fail_timeout=0;
}

server {
    listen 80;
    listen [::]:80;
    # need your current name
    server_name hram-nikola.ru www.hram-nikola.ru;
    return 302 https://$server_name$request_uri;
}

server {
    listen 443 ssl http2;
    listen [::]:443 ssl http2;

    # need your current name
    server_name hram-nikola.ru www.hram-nikola.ru;

    # need your current path to ssl`s
    ssl_certificate /etc/nginx/ssl/hram_nikola.crt;
    ssl_certificate_key /etc/nginx/ssl/hram_nikola.key;
    ssl_client_certificate /etc/nginx/ssl/cloudflare.crt;
    ssl_verify_client on;

    client_max_body_size 4G;

    # need your current path
    access_log /webapps/hram_nikola/logs/nginx-access.log;
    # need your current path
    error_log /webapps/hram_nikola/logs/nginx-error.log;

    # css and js
    location /static/ {
        # need your current path
        alias   /webapps/hram_nikola/church/Church/static/static_prod/;
    }

    # images and other media
    location /media/ {
        # need your current path
        alias   /webapps/hram_nikola/church/Church/static/;
    }

    location / {
        # an HTTP header important enough to have its own Wikipedia entry:
        #   http://en.wikipedia.org/wiki/X-Forwarded-For
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;

        # enable this if and only if you use HTTPS, this helps Rack
        # set the proper protocol for doing redirects:
        # proxy_set_header X-Forwarded-Proto https;

        # pass the Host: header from the client right along so redirects
        # can be set properly within the Rack application
        proxy_set_header Host $http_host;

        # we don't want nginx trying to do something clever with
        # redirects, we set the Host: header above already.
        proxy_redirect off;

        # set "proxy_buffering off" *only* for Rainbows! when doing
        # Comet/long-poll stuff.  It's also safe to set if you're
        # using only serving fast clients with Unicorn + nginx.
        # Otherwise you _want_ nginx to buffer responses to slow
        # clients, really.
        # proxy_buffering off;

        # Try to serve static files from nginx, no point in making an
        # *application* server like Unicorn/Rainbows! serve static files.
        if (!-f $request_filename) {
            # need string before "upstream" in first line on this file
            proxy_pass http://hram_nikola_server;
            break;
        }
    }

    # Error pages
    error_page 500 502 503 504 /500.html;
    location = /500.html {
        # need your current path
        root /webapps/hram_nikola/church/Church/static/;
    }
}

.modal_wrapper {
	position: fixed;
	width: inherit;
	height: inherit;
	background: rgb(0, 0, 0, 0.4);
	display: none;
	align-items: center;
	justify-items: center;
}

@keyframes scaleWindow {
	from {
		transform: scale(0);
	} to {
		transform: scale(1);
	}
}

.modal_wrapper .modal_window {
	transform: scale(1);
	border-radius: 4px;
	background: #fff;
	width: 40%;
	height: 25%;
	padding: 15px;
	box-shadow: 4px 4px 6px 2px rgb(0, 0, 0, 0.8);
	display: grid;
	grid-template-rows: 10% 90%;
	align-items: end;
	color: #242424;
	animation: 0.3s linear 1 normal;
}

class Modal {
	constructor (modalWrapper, modalWindow) {
		this.modalWrapper = modalWrapper
		this.modalWindow = modalWindow
	}
	open = () => {
		this.modalWrapper.style.display = "grid"

		this.modalWindow.style.animationName = "scaleWindow"
		this.modalWindow.style.transform = "scale(1)"
	}
	close = () => {
		this.modalWrapper.style.display = "none"
	}
}

