function insertAfter(referenceNode, newNode) {
	referenceNode.parentNode.insertBefore(newNode, referenceNode.nextSibling);
}

function check_captcha() {
	var answ = document.getElementsByClassName("captcha_answer")[0].value
	var c_wrapper = document.getElementsByClassName("captcha_wrapper")[0]
	var dialog = document.getElementById("dialog")
	if (answ == true_answer) {
		c_wrapper.innerHTML = ` 
			<span class="captcha_success">✓</span>
			<input id="send_comment" type="submit" value="Комментировать"/>
		`
		delete_tablo = true
	} else {
		dialog.innerHTML = `
			<nobr style="color: #FF0000;">Лжешь!</nobr>
		`
	}
}

function edit_tablo_captcha() {
	let t = document.getElementById(rnd_tab_id)

	t.style.margin = '10px auto'
	t.style.width = '100px'
	t.style.height = '100px'
	t.style.border = '1px solid #AAAAAA'
	t.style.filter = 'blur(1px)'
}

function create_captcha_tablo() {
	tablo = document.getElementById(rnd_tab_id)
	tablo.innerHTML = `
		<canvas id="tablo"></canvas>
	`

	var canvas = document.getElementById("tablo");
	var ctx = canvas.getContext("2d");

	var tabw = tablo.getBoundingClientRect().width
	var tabh = tablo.getBoundingClientRect().height

	let iter = Math.floor(Math.random() * (5 - 2 + 1) ) + 2

	true_answer = iter

	var last = []

	var i = 0

	while (i < iter) {

		let radius = Math.floor(Math.random() * (25 - 10 + 1) ) + 10

		let maxx = (tabw - radius) 
		let maxy = (tabh - radius)

		let posx = Math.floor(Math.random() * (maxx - radius + 1) ) + radius
		let posy = Math.floor(Math.random() * (maxy - radius + 1) ) + radius

		let stop = false

		if (last != []) {

			let t = 0
			let count = last.length

			while (t < count) {
				difference = Math.hypot(posx - last[t][0], posy - last[t][1])

				let r = radius

				if (Math.round(difference) < r) {
					stop = true
					count = 0
				} 

				t += 1
			}

		} else {
			last.push([posx, posy])
		}

		if (stop == false) {
			last.push([posx, posy])

			ctx.beginPath();
			ctx.arc(posx, posy, radius, 0, 2 * Math.PI, false);
			ctx.fillStyle = "rgb(255,255,255,0.6)"
			ctx.strokeStyle = 'rgb(36,36,36,0.8)';
			ctx.stroke();
			ctx.fill();
			i += 1
		}
	}
}

