function reHtml(html) {
	var text = html
	var tag = false
	var _tag_ = ''

	for (var i = 0; i < html.length; i++) {
		if (html[i] == '<') {
			tag = true
		} else if (html[i] == '>') {
			_tag_ += html[i]
			text = text.replace(_tag_, '')
			_tag_ = ''
			tag = false
		}

		if (tag == true) {
			_tag_ += html[i]
		}
	}

	return text
}

function delete_substr(original, substr) {
	var upper = original.toUpperCase()
	original = original.split('')

	for (var s = substr.length - 1; s >= 0; s--) {
		var space = '|'.repeat(substr[s].length)
		var count = (upper.split(substr[s].toUpperCase())).length - 1

		for (var i = 0; i < count; i++) {
			upper = upper.replace(substr[s].toUpperCase(), space)
		}
	}

	for (var i = 0; i < upper.length; i++) {
		if (upper[i] == '|') {
			original[i]=''
		}
	}

	return original.join('')
}

