import pygame, random
from math import sqrt

class Ball(object):
	def __init__(self, pos, weight, vector, screen):
		super(Ball, self).__init__()
		self.pos = pos
		self.weight = weight
		self.width = 4 + self.weight
		self.vector = vector
		self.screen = screen
		self.objects = []
		self.setBody()
		self.setVectorProcent()
		self.setKineticEnergy()

	def setObjects(self, objects):
		self.objects = [obj for obj in objects if obj != self]

	def setKineticEnergy(self):
		self.speed = sum(self.vector) / 2
		self.kineticEnergy = self.weight * (self.speed ** 2) / 2

	def setVectorProcent(self):
		onePrc = sum(self.vector) / 100
		self.vectorProcent = [self.vector[0] / onePrc, self.vector[1] / onePrc]

	def setBody(self):
		self.body = pygame.Rect((self.pos[0] - self.width, self.pos[1] - self.width, self.width * 2, self.width * 2)) 

	def bySign(self, kE, speed):
		if kE < 0:
			if speed > 0:
				return -1
			elif speed < 0:
				return 1
		elif kE > 0:
			if speed > 0:
				return 1
			elif speed < 0:
				return -1
		return 1

	def vectorByVelocity(self, velocity):
		v0, v1 = self.vectorProcent
		onePrc = velocity / 100
		return onePrc * v0, onePrc * v1

	def getVectorBias(self, objX, objY):
		aX, aY = self.pos
		catet1, catet2 = aX - objX, aY - objY
		return (catet1 / abs(catet1)) if catet1 else catet1, (catet2 / abs(catet2)) if catet2 else catet2

	def objectCollision(self):
		for obj in self.objects:
			if self.body.colliderect(obj.body):
				biasToX, biasToY = self.getVectorBias(obj.pos[0], obj.pos[1])
				kE = self.kineticEnergy - obj.kineticEnergy
				v = sqrt(abs(kE * 2 / self.weight)) * self.bySign(kE, self.speed) / 2
				v0, v1 = self.vectorByVelocity(v * 2)
				self.vector[0], self.vector[1] = v0 + biasToX, v1 + biasToY
				self.setKineticEnergy()

	def move(self):
		self.pos[0] += self.vector[0]
		self.pos[1] += self.vector[1]

	def draw(self):
		self.setBody()
		self.move()
		self.objectCollision()

		pygame.draw.circle(self.screen, (0, 0, 0), self.pos, self.width)

import pygame, random
from math import sqrt

class Object(object):
	def __init__(self, pos, weight, isBigObject, vector, screen):
		super(Object, self).__init__()
		self.pos = pos
		self.weight = weight
		self.isBigObject = isBigObject
		self.screen = screen
		self.vector = vector
		self.objects = []

	def setObjects(self, objs):
		self.objects = [obj for obj in objs if obj != self]

	def getDist(self, pos1, pos2):
		x1, y1 = pos1
		x2, y2 = pos2
		catet1, catet2 = x1 - x2, y1 - y2
		return sqrt(catet1 ** 2 + catet2 ** 2) 

	def getVectorBias(self, objX, objY):
		aX, aY = self.pos
		catet1, catet2 = aX - objX, aY - objY
		return (catet1 / abs(catet1)) if catet1 else catet1, (catet2 / abs(catet2)) if catet2 else catet2

	def objectsImpact(self):
		for obj in self.objects:
			dist = self.getDist(self.pos, obj.pos) * 10000
			biasToX, biasToY = self.getVectorBias(*obj.pos)
			biasToX, biasToY = biasToX / dist * obj.weight, biasToY / dist * obj.weight
			self.vector[0] -= biasToX
			self.vector[1] -= biasToY

	def move(self):
		self.pos[0] += self.vector[0]
		self.pos[1] += self.vector[1]

		self.objectsImpact()

	def draw(self):
		if self.isBigObject:
			pygame.draw.circle(self.screen, (0, 0, 0), self.pos, 1)
			pygame.draw.circle(self.screen, (0, 0, 0), self.pos, 8, 1)
		else:
			pygame.draw.circle(self.screen, (0, 0, 0), self.pos, 4 + self.weight)

		self.move()

import random
from math import cos, sin, radians
from numba import njit

@njit
def getFluctuation(fluc, new):
	offset = random.randint(12, 32)
	if not new:
		if fluc == abs(fluc):
			return -fluc
		elif fluc != abs(fluc):
			return abs(fluc)
	else:
		if fluc == abs(fluc):
			return -offset
		elif fluc != abs(fluc):
			return offset

@njit(fastmath=True)
def FlucDots(radius, pos):
	fluctuation = getFluctuation([-1, 1][random.randint(0, 1)], True)
	flucLast = fluctuation
	flucRangeVector = [20, 80]
	flucRange = flucRangeVector[random.randint(0, 1)]
	flucOffset = radius
	dots, deg, i = [], 0, 0
	while (deg <= 350):
		dots.append((int(pos[0] + cos(radians(deg)) * flucOffset), int(pos[1] + sin(radians(deg)) * flucOffset)))

		if i == int(flucRange / 2):
			fluctuation = getFluctuation(fluctuation, False)
		elif i == flucRange:
			fluctuation = getFluctuation(flucLast, True)
			flucLast = fluctuation
			flucRange = flucRangeVector[random.randint(0, 1)]
			i = 0

		flucOffset += fluctuation		

		if i < int(flucRange / 2):
			fluctuation /= 2
		elif i > int(flucRange / 2):
			fluctuation *= 2

		i += 1
		deg += 1

	return dots

import pygame, random, math

class Star(object):
	def __init__(self, pos, radius, color):
		super(Star, self).__init__()
		self.__x, self.__y = pos
		self.__radius = [radius, radius / 2]
		self.__color = color
		self.__count = 5
		self.__angStep = 30

	def __getXY(self, ang, radius):
		x = self.__x + int(math.sin(ang) * radius)
		y = self.__y + int(math.cos(ang) * radius)

		return (x, y)

	def draw(self, screen):
		lX, lY = 0, 0
		ang = 0
		for i in range(self.__count ** 2):
			x, y = self.__getXY(ang=math.radians(ang), radius=self.__radius[0 if not i % 2 else 1])

			if i:
				pygame.draw.aaline(screen, self.__color, (lX, lY), (x, y))

			lX, lY = x, y
			ang += self.__angStep

