from bot import Bot
import random

class Evolution(object):
	def __init__(self):
		super(Evolution, self).__init__()

	def mutation(self, firstGen, secondGen):
		newGen = []
		for i in range(genLength):
			rnd = random.randint(-1, 1)
			if rnd == -1:
				# add gen by first genom
				newGen.append(firstGen[i])
			elif rnd == 1:
				# add gen by second genom
				newGen.append(secondGen[i])
			else:
				# set random gen
				newGen.append(randomGen())

		return newGen

	def selection(self, bots, aX, aY):
		dists = {bot.getDist(aX, aY): bot for bot in bots}
		sortedDists = sorted(dists.keys())
		# if first bot distance more 10
		if sortedDists[0] < 10:
			return sortedDists[0]

		for i in range(len(bots)):
			bots[i] = Bot(
				pos=wC,
				gen=self.mutation(dists[sortedDists[0]].gen, dists[sortedDists[1]].gen)
			)

import win32clipboard

def toBuffer(text):
	win32clipboard.OpenClipboard()
	win32clipboard.EmptyClipboard()
	win32clipboard.SetClipboardText(text)
	win32clipboard.CloseClipboard()

def fromBuffer():
	win32clipboard.OpenClipboard()
	return win32clipboard.GetClipboardData()

Наследование - "подключение" одного класса к другому, при котором первый становится дочерним, а второй - родительским. Суть просто в том, что дочерний класс имеет доступ к методам и свойствам родительского. Для наследования нужно в скобки дочке (дочерний класс) передать родителя (родительский класс). Вот пример:

class Parent():
	def __init__(self, color, width):
		self.color = color
		self.width = width

	def twoWidth(self):
		return self.width * 2

class Child(Parent):
	def getColor(self):
		return self.color()

child = Child("#242424", 30)
print(child.getColor()) => "#242424"

1. При наследовании родительский и дочерний класс имеют общий инит (метод конструктор), поэтому при инициализации дочернего мы в качестве параметров должны передать те параметры, что принимаются в конструкторе класса Parent.

2. Дочка имеет полный доступ к методам и свойствам родителя:

print(child.twoWidth()) => 60

3. При наследовании не нужно инициализировать родителя, ведь дочка фактически является продолжением родителя, а значит всё это в итоге один объект Child. Благодаря этому мы можем спокойно взаимодействовать в родителе с "self", который будет вести на весь объект Child.

Полиморфизм - разное поведение одного и того же метода в различных объектах. В примере метод "concat()":

class Test1():
	def concat(self, str1, str2):
		return f"{str1} & {str2}"

class Test2():
	def concat(self, str1, str2):
		return ord(str1[0]) + ord(str2[0])

test1 = Test1().concat("Roma", "Alex")
test2 = Test2().concat("Roma", "Alex")
print(test1) # Roma & Alex
print(test2) # 147

Классы в питоне записываются так:

class Parent():
	def __init__(self, color, width):
		self.color = color
		self.width = width

	def color(self):
		return self.color

"__init__" - метод конструктор, который принимает данные при инициализации класса:

parent = Parent(color="#242424", width=30)

Передавая параметры я просто так пишу color и width, это не обязательно, мне просто так удобнее.

